import{_ as a}from"./chunks/文件受限图.DsG20F9s.js";import{_ as i,o as t,c as l,a2 as r}from"./chunks/framework.DnrXFDHb.js";const h=JSON.parse('{"title":"Image Moderation और Access Mode","description":"","frontmatter":{},"headers":[],"relativePath":"hi/Safety/image-moderation-and-access-mode.md","filePath":"hi/Safety/image-moderation-and-access-mode.md","lastUpdated":1781962217000}'),d={name:"hi/Safety/image-moderation-and-access-mode.md"};function o(s,e,n,c,m,u){return t(),l("div",null,[...e[0]||(e[0]=[r('<h1 id="image-moderation-और-access-mode" tabindex="-1">Image Moderation और Access Mode <a class="header-anchor" href="#image-moderation-और-access-mode" aria-label="Permalink to &quot;Image Moderation और Access Mode&quot;">​</a></h1><p>Image moderation uploaded images को age rating देता है। Access mode तय करता है कि public access में कौन सी ratings दिख सकती हैं।</p><p>यह public gallery, public file URLs और random image API पर असर डालता है। Admin panel पर restriction नहीं लगती। Administrators सभी files देख और manage कर सकते हैं।</p><h2 id="कहाँ-सेट-करें" tabindex="-1">कहाँ सेट करें <a class="header-anchor" href="#कहाँ-सेट-करें" aria-label="Permalink to &quot;कहाँ सेट करें&quot;">​</a></h2><p>Admin panel खोलें, फिर यहाँ जाएँ:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>System Settings -&gt; Security Settings -&gt; Upload Management -&gt; Image Moderation</span></span></code></pre></div><p>मुख्य settings हैं:</p><ul><li>Access mode</li><li>Enable moderation</li><li>Moderation provider</li></ul><h2 id="access-mode-क्या-करता-है" tabindex="-1">Access Mode क्या करता है <a class="header-anchor" href="#access-mode-क्या-करता-है" aria-label="Permalink to &quot;Access Mode क्या करता है&quot;">​</a></h2><p>Access mode तय करता है कि कौन सी age ratings publicly दिख सकती हैं।</p><p>Current modes:</p><table tabindex="0"><thead><tr><th>Access Mode</th><th>Publicly Visible Ratings</th></tr></thead><tbody><tr><td>Adult mode</td><td>General, R12, R16, R18</td></tr><tr><td>Youth mode</td><td>General, R12, R16</td></tr><tr><td>Teen mode</td><td>General, R12</td></tr><tr><td>Child mode</td><td>केवल General</td></tr></tbody></table><p>Default <code>Adult mode</code> है।</p><p>Private sites या mature content वाली sites के लिए Adult mode ठीक हो सकता है। अगर public gallery ज़्यादा conservative रखनी है, तो Youth, Teen या Child mode चुनें।</p><h2 id="moderation-enable-करने-पर-क्या-होता-है" tabindex="-1">Moderation Enable करने पर क्या होता है <a class="header-anchor" href="#moderation-enable-करने-पर-क्या-होता-है" aria-label="Permalink to &quot;Moderation Enable करने पर क्या होता है&quot;">​</a></h2><p>Moderation enabled होने पर ImgBed upload के दौरान selected moderation provider को call करता है और detected age rating save करता है।</p><p>मुख्य ratings:</p><table tabindex="0"><thead><tr><th>Rating</th><th>Meaning</th></tr></thead><tbody><tr><td>General</td><td>Safe public content</td></tr><tr><td>R12</td><td>हल्का sensitive content</td></tr><tr><td>R16</td><td>मध्यम sensitive content</td></tr><tr><td>R18</td><td>Adult content</td></tr></tbody></table><p>Public access तय करते समय moderation result इस्तेमाल होता है।</p><p>अगर moderation enabled नहीं है, या पुरानी files में rating नहीं है, तो वे files unrated मानी जाती हैं। सिर्फ rating न होने की वजह से unrated files public gallery या random image API से automatically नहीं हटतीं।</p><h2 id="moderation-provider-चुनना" tabindex="-1">Moderation Provider चुनना <a class="header-anchor" href="#moderation-provider-चुनना" aria-label="Permalink to &quot;Moderation Provider चुनना&quot;">​</a></h2><p>Available providers में शामिल हैं:</p><ul><li>moderatecontent.com</li><li>nsfwjs</li><li>Sightengine</li></ul><p>हर provider की requirements अलग होती हैं:</p><ul><li>moderatecontent.com को आम तौर पर API Key चाहिए।</li><li>nsfwjs को आम तौर पर API endpoint URL चाहिए।</li><li>Sightengine को API user और API secret चाहिए।</li></ul><p>अपने account, availability और detection quality के हिसाब से provider चुनें। जब moderation enabled और सही तरह configured हो, ImgBed upload के दौरान image rating लिखने की कोशिश करता है।</p><h2 id="public-gallery-पर-असर" tabindex="-1">Public Gallery पर असर <a class="header-anchor" href="#public-gallery-पर-असर" aria-label="Permalink to &quot;Public Gallery पर असर&quot;">​</a></h2><p>Public gallery access mode के हिसाब से files filter करती है।</p><p>उदाहरण:</p><ul><li>Adult mode: R18 images दिख सकती हैं।</li><li>Youth mode: R18 images छिप जाती हैं।</li><li>Teen mode: R16 और R18 images छिप जाती हैं।</li><li>Child mode: केवल General images दिखती हैं।</li></ul><p>यह सिर्फ normal public access पर असर डालता है। Admin panel सभी files दिखाता रहेगा।</p><h2 id="public-file-urls-पर-असर" tabindex="-1">Public File URLs पर असर <a class="header-anchor" href="#public-file-urls-पर-असर" aria-label="Permalink to &quot;Public File URLs पर असर&quot;">​</a></h2><p>Public file URLs वे direct image links हैं जिन्हें visitors खोलते हैं।</p><p>अगर file rating current access mode में allowed है, तो ImgBed original image return करता है।</p><p>अगर rating allowed level से ऊपर है, तो normal public access original image return नहीं करता। इसके बजाय ImgBed configured blocked result या blocked fallback image return करता है।</p><p>उदाहरण:</p><ul><li>Current mode <code>Child mode</code> है।</li><li>एक image की rating R18 है।</li><li>Visitor public URL direct खोलता है।</li><li>ImgBed उस visitor को R18 original image return नहीं करता।</li></ul><p><img src="'+a+'" alt="Restricted file image" loading="lazy"></p><p>Admin panel में files देखने वाले administrators पर यह restriction लागू नहीं होती।</p><h2 id="random-image-api-पर-असर" tabindex="-1">Random Image API पर असर <a class="header-anchor" href="#random-image-api-पर-असर" aria-label="Permalink to &quot;Random Image API पर असर&quot;">​</a></h2><p>Random image API भी access mode के हिसाब से candidate pool filter करता है।</p><p>Child mode में random images केवल General-rated files से चुनी जाती हैं।</p><p>Youth mode में random images General, R12 और R16 files से आ सकती हैं, लेकिन R18 files से नहीं।</p><p>इससे random image API public gallery restrictions bypass नहीं कर पाता।</p><h2 id="list-rules-से-संबंध" tabindex="-1">List Rules से संबंध <a class="header-anchor" href="#list-rules-से-संबंध" aria-label="Permalink to &quot;List Rules से संबंध&quot;">​</a></h2><p>Access mode अकेला public access rule नहीं है। यह allow/block list rules के साथ मिलकर काम करता है।</p><p>सरल रूप में:</p><ul><li>Allowlisted content पहले public माना जाता है।</li><li>Blocklisted content regular visitors द्वारा सीधे नहीं देखा जा सकता।</li><li>जो content किसी भी list में नहीं है, उसे फिर access mode के हिसाब से check किया जाता है।</li></ul><p>अगर कोई image age rating और list rules दोनों से restricted है, तो regular visitors original file direct नहीं देख पाएँगे।</p><h2 id="recommended-settings" tabindex="-1">Recommended Settings <a class="header-anchor" href="#recommended-settings" aria-label="Permalink to &quot;Recommended Settings&quot;">​</a></h2><p>Public sites के लिए:</p><ul><li>Moderation enable करें।</li><li>Site audience के हिसाब से access mode चुनें।</li><li>All-age visitors के लिए Child mode या Teen mode इस्तेमाल करें।</li><li>अगर mature content publicly नहीं दिखाना चाहते, तो Adult mode से बचें।</li><li>Admin panel में file ratings review करें और ज़रूरत पड़ने पर manually adjust करें।</li></ul><p>Private या personal sites के लिए:</p><ul><li>Adult mode आम तौर पर ठीक रहता है।</li><li>उपयोगी लगे तो moderation enable करें।</li><li>Admin panel में ratings review और adjust करते रहें।</li></ul><h2 id="faq" tabindex="-1">FAQ <a class="header-anchor" href="#faq" aria-label="Permalink to &quot;FAQ&quot;">​</a></h2><h3 id="access-mode-बदलने-के-बाद-क्या-files-admin-panel-से-गायब-हो-जाएँगी" tabindex="-1">Access Mode बदलने के बाद क्या files Admin Panel से गायब हो जाएँगी? <a class="header-anchor" href="#access-mode-बदलने-के-बाद-क्या-files-admin-panel-से-गायब-हो-जाएँगी" aria-label="Permalink to &quot;Access Mode बदलने के बाद क्या files Admin Panel से गायब हो जाएँगी?&quot;">​</a></h3><p>नहीं।</p><p>Access mode केवल normal public access पर असर डालता है। Admin panel पर इसका असर नहीं होता।</p><h3 id="child-mode-पर-switch-करने-के-बाद-public-gallery-में-कम-images-क्यों-दिखीं" tabindex="-1">Child Mode पर switch करने के बाद Public Gallery में कम Images क्यों दिखीं? <a class="header-anchor" href="#child-mode-पर-switch-करने-के-बाद-public-gallery-में-कम-images-क्यों-दिखीं" aria-label="Permalink to &quot;Child Mode पर switch करने के बाद Public Gallery में कम Images क्यों दिखीं?&quot;">​</a></h3><p>Child mode केवल General-rated files को publicly दिखाता है। R12, R16 और R18 files filter हो जाती हैं।</p><h3 id="क्या-public-urls-अभी-भी-adult-images-खोल-सकते-हैं" tabindex="-1">क्या Public URLs अभी भी Adult Images खोल सकते हैं? <a class="header-anchor" href="#क्या-public-urls-अभी-भी-adult-images-खोल-सकते-हैं" aria-label="Permalink to &quot;क्या Public URLs अभी भी Adult Images खोल सकते हैं?&quot;">​</a></h3><p>अगर current access mode उस rating को allow नहीं करता, तो normal public URLs original image return नहीं करते।</p><h3 id="क्या-random-image-api-restricted-images-return-कर-सकता-है" tabindex="-1">क्या Random Image API Restricted Images return कर सकता है? <a class="header-anchor" href="#क्या-random-image-api-restricted-images-return-कर-सकता-है" aria-label="Permalink to &quot;क्या Random Image API Restricted Images return कर सकता है?&quot;">​</a></h3><p>नहीं।</p><p>Random image API current access mode के हिसाब से candidates filter करता है।</p><h3 id="पुरानी-unrated-images-का-क्या-होगा" tabindex="-1">पुरानी Unrated Images का क्या होगा? <a class="header-anchor" href="#पुरानी-unrated-images-का-क्या-होगा" aria-label="Permalink to &quot;पुरानी Unrated Images का क्या होगा?&quot;">​</a></h3><p>Unrated images सिर्फ moderation result न होने की वजह से automatically hidden नहीं होतीं। आप बाद में admin panel में उनकी ratings adjust कर सकते हैं।</p>',67)])])}const b=i(d,[["render",o]]);export{h as __pageData,b as default};
